1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
7	const CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUES: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	  moonstone: 250,
28	};
29	
30	const DEDUCTIBLE = 100;
31	
32	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
33	  rune: 60,
34	  moonstone: 60,
35	};
36	
37	function calculateBasePremium(items: any[]): number {
38	  const countsByType: Record<string, number> = {};
39	  for (const item of items) {
40	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
41	  }
42	
43	  let total = 0;
44	  for (const type of Object.keys(countsByType)) {
45	    const count = countsByType[type];
46	    if (count === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
47	      total += COMPONENT_BLOCK_PREMIUM[type];
48	    } else {
49	      total += count * BASE_PREMIUMS[type];
50	    }
51	  }
52	  return total;
53	}
54	
55	function calculateItemSurcharges(items: any[]): number {
56	  let surcharges = 0;
57	  for (const item of items) {
58	    const itemBase = BASE_PREMIUMS[item.type];
59	    if (item.cursed) {
60	      surcharges += itemBase * CURSE_SURCHARGE_RATE;
61	    }
62	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
63	      surcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
64	    }
65	  }
66	  return surcharges;
67	}
68	
69	function calculatePremium(items: any[], customer: any, isFollowUp: boolean): number {
70	  const basePremium = calculateBasePremium(items);
71	  const itemSurcharges = calculateItemSurcharges(items);
72	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
73	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
74	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
75	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
76	}
77	
78	function reimbursementRateFor(item: any): number {
79	  if (item && item.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD) {
80	    return CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE;
81	  }
82	  return 1;
83	}
84	
85	function calculateDamagePayout(damage: any, policyItems: any[]): number {
86	  const matchedItem = policyItems.find((item: any) => item.type === damage.itemType);
87	  return damage.amount * reimbursementRateFor(matchedItem) - DEDUCTIBLE;
88	}
89	
90	function processClaim(
91	  policy: { items: any[]; insuranceSum: number; remainingCap: number },
92	  incident: any,
93	): { payout: number; remainingCap: number } {
94	  const totalPayout = Math.floor(
95	    incident.damages.reduce(
96	      (sum: number, damage: any) => sum + calculateDamagePayout(damage, policy.items),
97	      0,
98	    )
99	  );
100	  const clampedPayout = Math.min(totalPayout, policy.remainingCap);
101	  policy.remainingCap -= clampedPayout;
102	  return { payout: clampedPayout, remainingCap: policy.remainingCap };
103	}
104	
105	export function processScenario(scenario: any): unknown {
106	  const { customer } = scenario;
107	  const results: any[] = [];
108	  const policies: { items: any[]; insuranceSum: number; remainingCap: number }[] = [];
109	  let quotesSeen = 0;
110	  for (const step of scenario.steps) {
111	    if (step.op === "claim") {
112	      results.push(processClaim(policies[step.policy], step.incident));
113	    } else {
114	      const isFollowUp = quotesSeen > 0;
115	      const premium = calculatePremium(step.items, customer, isFollowUp);
116	      results.push({ premium });
117	      const insuranceSum = step.items.reduce(
118	        (sum: number, item: any) => sum + INSURANCE_VALUES[item.type],
119	        0
120	      );
121	      policies.push({ items: step.items, insuranceSum, remainingCap: 2 * insuranceSum });
122	      quotesSeen++;
123	    }
124	  }
125	  return { results };
126	}
